sql:
SELECT DISTINCT email 
FROM comments 
WHERE status IN ('pending', 'rejected');

SELECT comments.name, content_types.type_name, comments.date_submitted, comments.comment
FROM comments
INNER JOIN content_types ON comments.content_type_id = content_types.content_type_id;

SELECT AVG(num_comments) as avg_comments_per_user
FROM (
    SELECT user_id, COUNT(comment_id) as num_comments
    FROM comments
    GROUP BY user_id
);

SELECT date_submitted, comment
FROM comments
ORDER BY date_submitted DESC;

SELECT comment_id 
FROM comments 
WHERE content_type_id = 1;

SELECT user_id, COUNT(log_id) AS Total_Moderations
FROM moderation_logs
GROUP BY user_id;

external_knowledge:
- 'last month' is considered as the time period starting from the current date and going back 30 days (date('now','-1 month')); 
- 'public comments' means comments that are visible to everyone (is_public = 1); 
- 'approved comments' means comments that have been manually reviewed and validated (is_approved = 1); 
- 'reported more than 20 times' refers to the number of times users have flagged a comment as spam or reported it (reported_count > 20).
